public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity, int userId)
{
    using (var dbContext = new EventBookingContext())
    {
        // Start a transaction
        using (var transaction = await dbContext.Database.BeginTransactionAsync())
        {
            try
            {
                // Load the event with a row lock to ensure concurrency
                var eventEntity = await dbContext.Events
                    .Where(e => e.EventId == eventId)
                    .FirstOrDefaultAsync();

                if (eventEntity == null)
                    throw new Exception("Event not found.");

                // Check if enough seats are available
                if (eventEntity.AvailableSeats < quantity)
                    return false;

                // Deduct the purchased quantity from available seats
                eventEntity.AvailableSeats -= quantity;

                // Add a new ticket purchase record
                var ticketPurchase = new TicketPurchase
                {
                    EventId = eventId,
                    UserId = userId,
                    Quantity = quantity,
                    PurchaseDate = DateTime.UtcNow
                };
                dbContext.TicketPurchases.Add(ticketPurchase);

                // Save changes to the database
                await dbContext.SaveChangesAsync();

                // Commit the transaction
                await transaction.CommitAsync();
                return true;
            }
            catch
            {
                // Rollback the transaction in case of an error
                await transaction.RollbackAsync();
                return false;
            }
        }
    }
